-- Índices para transactions (filtros por status, type, createdAt)
CREATE INDEX IF NOT EXISTS idx_transactions_status ON transactions(status);
CREATE INDEX IF NOT EXISTS idx_transactions_type ON transactions(type);
CREATE INDEX IF NOT EXISTS idx_transactions_created_at ON transactions(createdAt);

-- Índices para reservations (filtros por status, created_at, productId)
CREATE INDEX IF NOT EXISTS idx_reservations_status ON reservations(status);
