-- Índices para TPV: tpv_sales (filtros por sessionId, createdAt)
CREATE INDEX IF NOT EXISTS idx_tpv_sales_session_id ON tpv_sales(session_id);
CREATE INDEX IF NOT EXISTS idx_tpv_sales_created_at ON tpv_sales(created_at);

-- Índices para products (filtros por isActive, isPresentialSale)
CREATE INDEX IF NOT EXISTS idx_experiences_active_presential ON experiences(is_active, is_presential_sale);
CREATE INDEX IF NOT EXISTS idx_packs_active_presential ON packs(is_active, is_presential_sale);
CREATE INDEX IF NOT EXISTS idx_spa_treatments_active_presential ON spa_treatments(is_active, is_presential_sale);
CREATE INDEX IF NOT EXISTS idx_room_types_active_presential ON room_types(is_active, is_presential_sale);

-- Índices para crmActivityLog (filtros por createdAt)
CREATE INDEX IF NOT EXISTS idx_crm_activity_log_created_at ON crm_activity_log(createdAt);

